export enum GameState {
  MENU = 'MENU',
  PLAYING = 'PLAYING',
  GAME_OVER = 'GAME_OVER'
}

export interface Question {
  text: string;
  answer: number;
  options: number[]; // The values displayed on falling blocks
}

export interface BlockEntity {
  id: string;
  x: number; // Percentage 0-100
  y: number; // Percentage 0-100
  value: number;
  width: number; // Percentage
  height: number; // Percentage (relative to screen aspect)
  isCorrect: boolean;
}

export interface PlayerEntity {
  x: number; // Percentage 0-100 (center point)
  width: number; // Percentage
}

export interface GameConfig {
  speedBase: number; // Speed multiplier
  spawnRate: number; // ms
}

import { Question } from '../types';

export const generateQuestion = (score: number): Question => {
  // Difficulty scales with score
  const difficulty = Math.min(Math.floor(score / 5), 10);

  const operations = ['+', '-'];
  if (difficulty > 3) operations.push('*');

  const operator = operations[Math.floor(Math.random() * operations.length)];

  let a = 0, b = 0, answer = 0;
  let text = '';

  // Generate numbers based on operator and difficulty
  switch (operator) {
    case '+':
      a = Math.floor(Math.random() * (10 + difficulty * 5)) + 1;
      b = Math.floor(Math.random() * (10 + difficulty * 5)) + 1;
      answer = a + b;
      text = `${a} + ${b} = ?`;
      break;
    case '-':
      a = Math.floor(Math.random() * (10 + difficulty * 5)) + 5;
      b = Math.floor(Math.random() * a); // Ensure positive result
      answer = a - b;
      text = `${a} - ${b} = ?`;
      break;
    case '*':
      a = Math.floor(Math.random() * (3 + difficulty)) + 2;
      b = Math.floor(Math.random() * (5 + difficulty)) + 1;
      answer = a * b;
      text = `${a} × ${b} = ?`;
      break;
  }

  // Generate wrong options that are close to the answer
  const options = new Set<number>();
  options.add(answer);

  while (options.size < 3) {
    const offset = Math.floor(Math.random() * 5) + 1;
    const direction = Math.random() > 0.5 ? 1 : -1;
    const wrong = answer + (offset * direction);
    if (wrong >= 0) options.add(wrong);
  }

  // Convert Set to Array and shuffle
  const shuffledOptions = Array.from(options).sort(() => Math.random() - 0.5);

  return {
    text,
    answer,
    options: shuffledOptions
  };
};

import React, { useEffect, useRef } from 'react';
import { GameState, Question, BlockEntity, PlayerEntity } from '../types';
import { generateQuestion } from '../services/mathService';

interface GameEngineProps {
  gameState: GameState;
  onScoreUpdate: (score: number) => void;
  onGameOver: (finalScore: number) => void;
  onQuestionUpdate: (q: string) => void;
}

const GameEngine: React.FC<GameEngineProps> = ({ 
  gameState, 
  onScoreUpdate, 
  onGameOver,
  onQuestionUpdate
}) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const requestRef = useRef<number>(0);

  // Mutable game state (refs) to avoid re-renders during loop
  const scoreRef = useRef(0);
  const playerRef = useRef<PlayerEntity>({ x: 50, width: 15 });
  const blocksRef = useRef<BlockEntity[]>([]);
  const currentQuestionRef = useRef<Question | null>(null);
  const speedMultiplierRef = useRef(1);
  const lastSpawnTimeRef = useRef(0);

  // Control flags
  const isMovingLeft = useRef(false);
  const isMovingRight = useRef(false);

  // Initialize a new round/question
  const spawnQuestion = () => {
    const q = generateQuestion(scoreRef.current);
    currentQuestionRef.current = q;
    onQuestionUpdate(q.text);

    // Create 2 or 3 blocks depending on options
    // To make it playable, we distribute them evenly across the width
    const laneCount = q.options.length;
    const laneWidth = 100 / laneCount;

    const newBlocks: BlockEntity[] = q.options.map((opt, index) => {
      // Add some randomness to X within the lane
      const laneCenter = (index * laneWidth) + (laneWidth / 2);
      const randomOffset = (Math.random() * 10) - 5; 

      return {
        id: Math.random().toString(36).substr(2, 9),
        x: Math.max(10, Math.min(90, laneCenter + randomOffset)), // Clamp between 10-90%
        y: -20 - (Math.random() * 20), // Start above screen, staggered
        value: opt,
        width: 12, // Width in %
        height: 0, // Will be calculated based on aspect ratio in draw
        isCorrect: opt === q.answer
      };
    });

    blocksRef.current = newBlocks;
  };

  const handleInput = (clientX: number) => {
    if (gameState !== GameState.PLAYING || !canvasRef.current) return;
    const rect = canvasRef.current.getBoundingClientRect();
    const x = clientX - rect.left;
    const percentage = (x / rect.width) * 100;
    playerRef.current.x = Math.max(5, Math.min(95, percentage));
  };

  // Keyboard controls
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (gameState !== GameState.PLAYING) return;
      if (e.key === 'ArrowLeft' || e.key === 'a') isMovingLeft.current = true;
      if (e.key === 'ArrowRight' || e.key === 'd') isMovingRight.current = true;
    };

    const handleKeyUp = (e: KeyboardEvent) => {
      if (e.key === 'ArrowLeft' || e.key === 'a') isMovingLeft.current = false;
      if (e.key === 'ArrowRight' || e.key === 'd') isMovingRight.current = false;
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, [gameState]);

  // Touch/Mouse controls
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const onTouchMove = (e: TouchEvent) => {
      e.preventDefault(); // Prevent scrolling
      handleInput(e.touches[0].clientX);
    };
    const onMouseMove = (e: MouseEvent) => {
      // Only move if mouse is down or just hovering? 
      // For desktop, hovering is fine.
      if (e.buttons === 1) {
          handleInput(e.clientX);
      }
    };

    // For "tap to move" style on desktop, we might just want movement to follow cursor
    // But let's stick to drag/buttons for consistency.
    // Actually, mouse following is smoother for this type of game.
    const onMouseMoveHover = (e: MouseEvent) => {
         handleInput(e.clientX);
    };

    canvas.addEventListener('touchmove', onTouchMove, { passive: false });
    canvas.addEventListener('mousemove', onMouseMoveHover);

    return () => {
      canvas.removeEventListener('touchmove', onTouchMove);
      canvas.removeEventListener('mousemove', onMouseMoveHover);
    };
  }, [gameState]);

  // Main Game Loop
  const update = (time: number) => {
    if (gameState !== GameState.PLAYING) return;

    // Keyboard Movement Logic
    const moveSpeed = 1.5; // % per frame
    if (isMovingLeft.current) playerRef.current.x = Math.max(5, playerRef.current.x - moveSpeed);
    if (isMovingRight.current) playerRef.current.x = Math.min(95, playerRef.current.x + moveSpeed);

    // Base falling speed increases with score
    const baseSpeed = 0.3 + (scoreRef.current * 0.02);

    // Update Blocks
    const player = playerRef.current;
    let hitBlockIndex = -1;
    let missedAll = true;

    // We check if blocks are still active
    const activeBlocks = blocksRef.current.filter(b => b.y < 120);

    // If no blocks left and we didn't hit anything, spawn new ones (this handles the "missed all" case if we want to just respawn, or fail)
    // For this game: If all blocks pass the player and none were hit, it's a "Game Over" because you missed the answer.
    const remainingBlocks = [];

    for (let i = 0; i < blocksRef.current.length; i++) {
      const block = blocksRef.current[i];
      block.y += baseSpeed;

      // Collision Detection (Simple AABB)
      // Player Y is fixed at bottom ~90%
      const playerYTop = 85; 
      const playerYBottom = 95;
      const blockBottom = block.y + 6; // approximate height in %

      const xOverlap = Math.abs(block.x - player.x) < (block.width/2 + player.width/2);
      const yOverlap = blockBottom > playerYTop && block.y < playerYBottom;

      if (xOverlap && yOverlap) {
        hitBlockIndex = i;
        break; // Handle collision immediately
      }

      if (block.y < 110) {
        remainingBlocks.push(block);
      }
    }

    blocksRef.current = remainingBlocks;

    // Handle Collision Result
    if (hitBlockIndex !== -1) {
      const hitBlock = blocksRef.current[hitBlockIndex];
      if (hitBlock.isCorrect) {
        // Correct!
        scoreRef.current += 1;
        onScoreUpdate(scoreRef.current);
        // Clear blocks to force respawn
        blocksRef.current = []; 
        spawnQuestion();
      } else {
        // Wrong!
        onGameOver(scoreRef.current);
        return; // Stop loop
      }
    } else if (blocksRef.current.length === 0) {
      // All blocks gone and no hit?
      // If we are in "between questions" state this is fine, but if we just drained the array...
      // Since we clear array on success, this block only executes if they fell off screen
      // Which means the player missed the correct answer.
      onGameOver(scoreRef.current);
      return; 
    }

    draw();
    requestRef.current = requestAnimationFrame(update);
  };

  const draw = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const w = canvas.width;
    const h = canvas.height;

    // Clear
    ctx.clearRect(0, 0, w, h);

    // Draw Lanes (Optional visual aid)
    ctx.strokeStyle = 'rgba(255, 255, 255, 0.05)';
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.moveTo(w * 0.33, 0); ctx.lineTo(w * 0.33, h);
    ctx.moveTo(w * 0.66, 0); ctx.lineTo(w * 0.66, h);
    ctx.stroke();

    // Draw Player
    const px = (playerRef.current.x / 100) * w;
    const py = h * 0.9; // Fixed Y position
    const pWidth = (playerRef.current.width / 100) * w;
    const pHeight = pWidth; // Square character

    ctx.fillStyle = '#06b6d4'; // Cyan
    ctx.shadowBlur = 15;
    ctx.shadowColor = '#06b6d4';

    // Draw Triangle Ship
    ctx.beginPath();
    ctx.moveTo(px, py - pHeight/2);
    ctx.lineTo(px - pWidth/2, py + pHeight/2);
    ctx.lineTo(px + pWidth/2, py + pHeight/2);
    ctx.closePath();
    ctx.fill();
    ctx.shadowBlur = 0;

    // Draw Blocks
    blocksRef.current.forEach(block => {
      const bx = (block.x / 100) * w;
      const by = (block.y / 100) * h;
      const bW = (block.width / 100) * w;
      const bH = bW * 0.8; // Aspect ratio

      // Box
      ctx.fillStyle = 'white';
      ctx.beginPath();
      ctx.roundRect(bx - bW/2, by, bW, bH, 8);
      ctx.fill();

      // Text
      ctx.fillStyle = '#1e1b4b';
      ctx.font = `bold ${Math.floor(bH * 0.6)}px Fredoka`;
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillText(block.value.toString(), bx, by + bH/2);
    });
  };

  // Resize handler
  useEffect(() => {
    const resize = () => {
      if (canvasRef.current) {
        // High DPI support
        const dpr = window.devicePixelRatio || 1;
        canvasRef.current.width = window.innerWidth * dpr;
        canvasRef.current.height = window.innerHeight * dpr;

        const ctx = canvasRef.current.getContext('2d');
        if (ctx) ctx.scale(dpr, dpr);

        // Fix style width/height to match window
        canvasRef.current.style.width = `${window.innerWidth}px`;
        canvasRef.current.style.height = `${window.innerHeight}px`;

        // Re-draw immediately
        draw();
      }
    };
    window.addEventListener('resize', resize);
    resize();
    return () => window.removeEventListener('resize', resize);
  }, []);

  // Game Lifecycle
  useEffect(() => {
    if (gameState === GameState.PLAYING) {
      scoreRef.current = 0;
      playerRef.current = { x: 50, width: 15 };
      blocksRef.current = [];
      spawnQuestion();
      requestRef.current = requestAnimationFrame(update);
    } else {
      cancelAnimationFrame(requestRef.current);
    }

    return () => cancelAnimationFrame(requestRef.current);
  }, [gameState]);

  // Initial draw for background
  useEffect(() => {
    if (gameState === GameState.MENU) {
        draw();
    }
  }, [gameState]);

  return (
    <canvas
      ref={canvasRef}
      className="absolute top-0 left-0 w-full h-full block touch-none"
    />
  );
};

