import React, { useEffect, useRef } from 'react';
import { GameState, BlockEntity, PlayerEntity } from '../types';
import { generateQuestion } from '../services/mathService';

interface GameEngineProps {
  gameState: GameState;
  onScoreUpdate: (score: number) => void;
  onGameOver: (finalScore: number) => void;
  onQuestionUpdate: (q: string) => void;
}

const GameEngine: React.FC<GameEngineProps> = ({ 
  gameState, 
  onScoreUpdate, 
  onGameOver,
  onQuestionUpdate
}) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const requestRef = useRef<number>(0);
  const previousTimeRef = useRef<number>(0);

  // Refs for game state to avoid closure staleness in loop
  const gameStateRef = useRef(gameState);
  const scoreRef = useRef(0);

  // Game Entities
  const playerRef = useRef<PlayerEntity>({ x: 50, width: 12 });
  const blocksRef = useRef<BlockEntity[]>([]);

  // Input State
  const isMovingLeft = useRef(false);
  const isMovingRight = useRef(false);

  // Sync ref with prop
  useEffect(() => {
    gameStateRef.current = gameState;
  }, [gameState]);

  // Initialize a new round/question
  const spawnQuestion = () => {
    const q = generateQuestion(scoreRef.current);
    onQuestionUpdate(q.text);

    const laneCount = q.options.length;
    // Distribute lanes across 80% of screen width (10% padding each side)
    const availableWidth = 80; 
    const startX = 10;
    const laneWidth = availableWidth / laneCount;

    const newBlocks: BlockEntity[] = q.options.map((opt, index) => {
      const laneCenter = startX + (index * laneWidth) + (laneWidth / 2);
      const randomOffset = (Math.random() * 4) - 2; // Small random jitter

      return {
        id: Math.random().toString(36).substr(2, 9),
        x: laneCenter + randomOffset,
        y: -30 - (Math.random() * 15), // Start further up
        value: opt,
        width: 15, // Block width %
        height: 0, 
        isCorrect: opt === q.answer
      };
    });

    blocksRef.current = newBlocks;
  };

  const handleInput = (clientX: number) => {
    if (gameStateRef.current !== GameState.PLAYING || !canvasRef.current) return;
    const rect = canvasRef.current.getBoundingClientRect();
    const x = clientX - rect.left;
    const percentage = (x / rect.width) * 100;
    playerRef.current.x = Math.max(8, Math.min(92, percentage));
  };

  // Keyboard controls
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (gameStateRef.current !== GameState.PLAYING) return;
      if (e.key === 'ArrowLeft' || e.key === 'a') isMovingLeft.current = true;
      if (e.key === 'ArrowRight' || e.key === 'd') isMovingRight.current = true;
    };

    const handleKeyUp = (e: KeyboardEvent) => {
      if (e.key === 'ArrowLeft' || e.key === 'a') isMovingLeft.current = false;
      if (e.key === 'ArrowRight' || e.key === 'd') isMovingRight.current = false;
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, []); // Empty dependency array, using refs

  // Mouse/Touch controls
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const onTouchMove = (e: TouchEvent) => {
      e.preventDefault(); 
      handleInput(e.touches[0].clientX);
    };

    const onMouseMove = (e: MouseEvent) => {
      if (e.buttons === 1) { // Click and drag
        handleInput(e.clientX);
      }
    };

    const onHoverMove = (e: MouseEvent) => {
       // Enable hover tracking for easier desktop play
       handleInput(e.clientX);
    };

    canvas.addEventListener('touchmove', onTouchMove, { passive: false });
    canvas.addEventListener('mousemove', onMouseMove);
    canvas.addEventListener('mousemove', onHoverMove);

    return () => {
      canvas.removeEventListener('touchmove', onTouchMove);
      canvas.removeEventListener('mousemove', onMouseMove);
      canvas.removeEventListener('mousemove', onHoverMove);
    };
  }, []);

  // Main Game Loop
  const animate = (time: number) => {
    if (previousTimeRef.current === 0) previousTimeRef.current = time;
    const deltaTime = time - previousTimeRef.current;
    previousTimeRef.current = time;

    // Cap delta time to prevent physics explosions on lag
    const dt = Math.min(deltaTime, 64); 

    if (gameStateRef.current === GameState.PLAYING) {
      update(dt);
    }

    draw();
    requestRef.current = requestAnimationFrame(animate);
  };

  const update = (dt: number) => {
    // Normalizing speed: 60fps = 16.6ms per frame.
    const timeScale = dt / 16.66;

    // Player Movement
    const moveSpeed = 1.0 * timeScale;
    if (isMovingLeft.current) playerRef.current.x = Math.max(8, playerRef.current.x - moveSpeed);
    if (isMovingRight.current) playerRef.current.x = Math.min(92, playerRef.current.x + moveSpeed);

    // Block Movement
    // Speed increases with score
    const baseDropSpeed = (0.2 + (scoreRef.current * 0.025)) * timeScale;

    let hitBlock: BlockEntity | null = null;
    const nextBlocks: BlockEntity[] = [];

    const player = playerRef.current;

    // Player Hitbox (approximate vertical area for the emoji stack)
    // The visual stack is centered at 88% height.
    // Head ~82%, Body ~88%, Legs ~94%
    const playerTop = 80;
    const playerBottom = 96;

    for (const block of blocksRef.current) {
      block.y += baseDropSpeed;

      // Collision Detection
      if (!hitBlock) {
        // Horizontal overlap
        const xDist = Math.abs(block.x - player.x);
        const hitX = xDist < (block.width / 2 + player.width / 2);

        // Vertical overlap (block hitting the player's head/body)
        // Block "bottom" is y + height (approx 8-10%)
        const hitY = (block.y + 5) > playerTop && block.y < playerBottom;

        if (hitX && hitY) {
          hitBlock = block;
        }
      }

      // Keep block if it hasn't fallen too far
      if (block.y < 120) {
        nextBlocks.push(block);
      }
    }

    blocksRef.current = nextBlocks;

    // Handle Hits
    if (hitBlock) {
      if ((hitBlock as BlockEntity).isCorrect) {
        scoreRef.current += 1;
        onScoreUpdate(scoreRef.current);
        blocksRef.current = []; // Clear blocks for next round
        spawnQuestion();
      } else {
        onGameOver(scoreRef.current);
      }
      return;
    } 

    // Check if missed (all blocks gone and no hit)
    if (blocksRef.current.length === 0) {
       onGameOver(scoreRef.current);
    }
  };

  const draw = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const w = canvas.width;
    const h = canvas.height;

    // Clear canvas
    ctx.clearRect(0, 0, w, h);

    // Draw Player (Composite Emoji)
    const px = (playerRef.current.x / 100) * w;
    const py = h * 0.88; // Center of the character
    const size = Math.min(w, h) * 0.15; // Size relative to screen

    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';

    // Adjust font size
    ctx.font = `${size * 0.7}px serif`; 

    // Stack: Head, Body, Legs
    // We adjust offsets to make them look connected
    const spacing = size * 0.55; 
    const headY = py - spacing;
    const bodyY = py;
    const legsY = py + spacing;

    ctx.shadowColor = 'rgba(0,0,0,0.5)';
    ctx.shadowBlur = 15;

    ctx.fillText('😃', px, headY);
    ctx.fillText('👕', px, bodyY);
    ctx.fillText('👖', px, legsY);

    ctx.shadowBlur = 0;

    // Draw Blocks
    blocksRef.current.forEach(block => {
      const bx = (block.x / 100) * w;
      const by = (block.y / 100) * h;
      const bW = (block.width / 100) * w;
      const bH = bW * 0.8; 

      // Draw Block background
      ctx.fillStyle = 'white';
      ctx.beginPath();
      // roundRect fallback
      if (typeof ctx.roundRect === 'function') {
        ctx.roundRect(bx - bW/2, by, bW, bH, 12);
      } else {
        ctx.rect(bx - bW/2, by, bW, bH);
      }
      ctx.fill();

      // Draw Text
      ctx.fillStyle = '#1e1b4b'; // Dark blue text
      ctx.font = `bold ${Math.floor(bH * 0.5)}px "Fredoka", sans-serif`;
      ctx.fillText(block.value.toString(), bx, by + bH/2);
    });
  };

  // Resize handler
  useEffect(() => {
    const handleResize = () => {
      if (canvasRef.current) {
        const dpr = window.devicePixelRatio || 1;
        canvasRef.current.width = window.innerWidth * dpr;
        canvasRef.current.height = window.innerHeight * dpr;

        const ctx = canvasRef.current.getContext('2d');
        if (ctx) ctx.scale(dpr, dpr);

        canvasRef.current.style.width = `${window.innerWidth}px`;
        canvasRef.current.style.height = `${window.innerHeight}px`;
      }
    };

    window.addEventListener('resize', handleResize);
    handleResize(); // Initial size

    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // Game Lifecycle Management
  useEffect(() => {
    requestRef.current = requestAnimationFrame(animate);

    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, []); 

  // Reset Game
  useEffect(() => {
    if (gameState === GameState.PLAYING) {
      scoreRef.current = 0;
      playerRef.current = { x: 50, width: 12 };
      blocksRef.current = [];
      previousTimeRef.current = 0;
      spawnQuestion();
    }
  }, [gameState]);

  return (
    <canvas
      ref={canvasRef}
      className="absolute top-0 left-0 w-full h-full block touch-none"
    />
  );
};

export default GameEngine;
